import './CategorywiseExpenseChart.css';
import {
    PieChart,
    Pie,
    Tooltip,
    Legend,
    ResponsiveContainer
} from "recharts";

function CategorywiseExpenseChart({categoryData}) {
    const pieChartData = Object.entries(categoryData).map(
        ([category, amount]) => ({
            category,
            amount
        })
    );
    const category_colors = {
        Food: "#51E5FF",
        Transportation: "#51E5FF",
        Shopping: "#51E5FF",
        Entertainment: "#51E5FF",
        Bills: "#51E5FF",
        Healthcare: "#51E5FF",
        Education: "#51E5FF",
        Other: "#51E5FF"
    }
    return (
        <ResponsiveContainer
            width="100%"
            height={350}
        >
            <PieChart>
                <Pie
                    data={pieChartData}
                    dataKey="amount"
                    nameKey="category"
                    outerRadius={120}
                    label
                />
                    {pieChartData.map((entry, index) => (
                        <Cell
                            key={index}
                            fill={
                                category_colors[entry.category]
                                || "#94A3B8"
                            }
                        />
                    ))}
                <Tooltip />
                <Legend />
            </PieChart>
        </ResponsiveContainer>
    );
}
export default CategorywiseExpenseChart;
